import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const SubjectSelection = () => {
  const { courseId, yearId, semId } = useParams();
  const navigate = useNavigate();
  
  const subjects = [
    { id: 1, name: 'Mathematics', code: 'MATH101' },
    { id: 2, name: 'Physics', code: 'PHY101' },
    { id: 3, name: 'Chemistry', code: 'CHE101' },
    { id: 4, name: 'Programming', code: 'CSE101' }
  ];
  
  const handleSubjectClick = (subjectId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}/subject/${subjectId}`);
  };
  
  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}`);
  };
  
  return (
    <div style={styles.container}>
      <button onClick={handleBack} style={styles.backButton}>
        ← Back to Semesters
      </button>
      
      <div style={styles.header}>
        <h1>Semester {semId} - Subjects</h1>
        <p>Choose a subject to view materials</p>
      </div>
      
      <div style={styles.subjectsGrid}>
        {subjects.map(subject => (
          <div 
            key={subject.id}
            style={styles.subjectCard}
            onClick={() => handleSubjectClick(subject.id)}
          >
            <h3>{subject.name}</h3>
            <p style={styles.code}>{subject.code}</p>
            <p>4 Credits • Complete materials</p>
            <button style={styles.selectButton}>
              View Materials →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    marginBottom: '2rem'
  },
  header: {
    textAlign: 'center',
    marginBottom: '3rem',
    padding: '2rem',
    background: 'white',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  subjectsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))',
    gap: '1.5rem'
  },
  subjectCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'all 0.3s',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    }
  },
  code: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0.5rem 0'
  },
  selectButton: {
    marginTop: '1rem',
    padding: '0.75rem 1.5rem',
    background: 'linear-gradient(90deg, #f59e0b, #fbbf24)',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    width: '100%'
  }
};

export default SubjectSelection;
